text:
太阳系是一个以太阳为中心的引力束缚系统，八大行星沿各自的椭圆轨道运行，距离太阳越近的行星公转速度越快。下面这个交互式 3D 模型展示了各行星的相对位置、轨道和运动速度——你可以拖拽旋转视角，点击任意星球了解更多。

```show-widget
{"title":"solar_system_3d","widget_code":"<style>
canvas{display:block;width:100%!important;height:420px!important}
#controls{display:flex;align-items:center;gap:12px;padding:10px 0 0;font-size:13px;color:var(--color-text-secondary);flex-wrap:wrap}
#controls button{margin:0}
#info{min-height:20px;flex:1}
</style>
<canvas id="c"></canvas>
<div id="controls">
<button id="btn" onclick="togglePlay()">Pause</button>
<label style="display:flex;align-items:center;gap:6px;flex:1">Speed<input type="range" min="1" max="20" value="5" step="1" style="flex:1" oninput="speedMul=this.value*0.2;document.getElementById('spd').textContent=this.value+'x'"><span id="spd" style="min-width:28px">5x</span></label>
<span id="info" style="text-align:right"></span>
</div>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js" onload="init()"></script>
<script>
var scene,camera,renderer,controls;
var speedMul=1,playing=true,t=0;
var planets=[],clickTargets=[];
var raycaster,mouse;
var dragDist=0,startX=0,startY=0;

function init(){
if(!window.THREE||!THREE.OrbitControls)return;
var canvas=document.getElementById('c');
var W=canvas.clientWidth,H=420;
renderer=new THREE.WebGLRenderer({canvas:canvas,antialias:true,alpha:true});
renderer.setSize(W,H);
renderer.setPixelRatio(Math.min(devicePixelRatio,2));
scene=new THREE.Scene();
camera=new THREE.PerspectiveCamera(45,W/H,0.1,1000);
camera.position.set(0,18,32);
scene.add(new THREE.AmbientLight(0xffffff,0.35));
var sun=new THREE.DirectionalLight(0xffffff,0.9);
sun.position.set(5,8,5);
scene.add(sun);
controls=new THREE.OrbitControls(camera,canvas);
controls.enableDamping=true;
controls.dampingFactor=0.08;
controls.autoRotate=true;
controls.autoRotateSpeed=0.4;

raycaster=new THREE.Raycaster();
mouse=new THREE.Vector2();
canvas.addEventListener('mousedown',function(e){startX=e.clientX;startY=e.clientY;dragDist=0});
canvas.addEventListener('mousemove',function(e){dragDist+=Math.abs(e.clientX-startX)+Math.abs(e.clientY-startY)});
canvas.addEventListener('click',function(e){
if(dragDist>5)return;
var rect=canvas.getBoundingClientRect();
mouse.x=((e.clientX-rect.left)/rect.width)*2-1;
mouse.y=-((e.clientY-rect.top)/rect.height)*2+1;
raycaster.setFromCamera(mouse,camera);
var hits=raycaster.intersectObjects(clickTargets);
if(hits.length){
var n=hits[0].object.name;
window.__widgetSendMessage('详细介绍'+n+'的特征、轨道参数和有趣事实');
}
});

buildScene();
animate();
}

function buildScene(){
var sunGeo=new THREE.SphereGeometry(1.8,32,24);
var sunMat=new THREE.MeshBasicMaterial({color:0xEF9F27});
var sunMesh=new THREE.Mesh(sunGeo,sunMat);
sunMesh.name='太阳';
scene.add(sunMesh);
clickTargets.push(sunMesh);

var glowGeo=new THREE.SphereGeometry(2.2,24,16);
var glowMat=new THREE.MeshBasicMaterial({color:0xFAC775,transparent:true,opacity:0.15});
scene.add(new THREE.Mesh(glowGeo,glowMat));

var data=[
{name:'水星',color:0x888780,r:0.25,dist:3.2,speed:4.15,info:'最小最快'},
{name:'金星',color:0xD85A30,r:0.4,dist:4.8,speed:1.62,info:'最热行星'},
{name:'地球',color:0x378ADD,r:0.42,dist:6.5,speed:1.0,info:'我们的家园'},
{name:'火星',color:0xE24B4A,r:0.32,dist:8.2,speed:0.53,info:'红色星球'},
{name:'木星',color:0xD85A30,r:0.9,dist:11.5,speed:0.084,info:'最大行星'},
{name:'土星',color:0xEF9F27,r:0.78,dist:15,speed:0.034,info:'美丽光环'},
{name:'天王星',color:0x1D9E75,r:0.55,dist:18.5,speed:0.012,info:'侧躺旋转'},
{name:'海王星',color:0x378ADD,r:0.52,dist:22,speed:0.006,info:'最远行星'}
];

for(var i=0;i<data.length;i++){
var d=data[i];
var orbitGeo=new THREE.RingGeometry(d.dist-0.02,d.dist+0.02,96);
var orbitMat=new THREE.MeshBasicMaterial({color:0x888780,side:THREE.DoubleSide,transparent:true,opacity:0.12});
var orbit=new THREE.Mesh(orbitGeo,orbitMat);
orbit.rotation.x=-Math.PI/2;
scene.add(orbit);

var geo=new THREE.SphereGeometry(d.r,16,12);
var mat=new THREE.MeshLambertMaterial({color:d.color});
var mesh=new THREE.Mesh(geo,mat);
mesh.name=d.name;
scene.add(mesh);
clickTargets.push(mesh);

planets.push({mesh:mesh,dist:d.dist,speed:d.speed,offset:Math.random()*Math.PI*2});

if(d.name==='土星'){
var ringGeo=new THREE.RingGeometry(d.r+0.15,d.r+0.55,48);
var ringMat=new THREE.MeshBasicMaterial({color:0xFAC775,side:THREE.DoubleSide,transparent:true,opacity:0.45});
var ring=new THREE.Mesh(ringGeo,ringMat);
ring.rotation.x=-Math.PI*0.4;
mesh.add(ring);
}
}
}

function animate(){
requestAnimationFrame(animate);
if(playing){
t+=0.002*speedMul;
for(var i=0;i<planets.length;i++){
var p=planets[i];
var angle=t*p.speed+p.offset;
p.mesh.position.set(Math.cos(angle)*p.dist,0,Math.sin(angle)*p.dist);
p.mesh.rotation.y+=0.01;
}
}
controls.update();
renderer.render(scene,camera);
}

function togglePlay(){
playing=!playing;
document.getElementById('btn').textContent=playing?'Pause':'Play';
}

if(window.THREE&&THREE.OrbitControls)init();
</script>"}
```

模型中行星大小和轨道间距做了适当缩放以便观察（真实比例下内行星几乎不可见）。公转速度比例接近真实——水星最快，海王星最慢。拖拽可自由旋转视角，点击任意星球可以深入了解它的详细信息。
